from flask import Flask, render_template, request, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config["SQLALCHEMY_DATABASE_URI"] = "sqlite:///attendance.db"
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)

class Attendance(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    student_id = db.Column(db.Integer, db.ForeignKey("user.id"), nullable=False)
    date = db.Column(db.DateTime, nullable=False)
    status = db.Column(db.String(80), nullable=False)

@app.route("/register", methods=["GET", "POST"])
def register_page():
    if request.method == "POST":
        username = request.form["username"]
        email = request.form["email"]
        password = request.form["password"]
        confirm_password = request.form["confirm_password"]

        if password == confirm_password:
            user = User.query.filter_by(email=email).first()
            if user:
                return "Email already exists"
            new_user = User(username=username, email=email, password=generate_password_hash(password))
            db.session.add(new_user)
            db.session.commit()
            return redirect(url_for("login"))
        else:
            return "Passwords do not match"
    return render_template("register.html")

@app.route("/login", methods=["GET", "POST"])
def login_page():
    if request.method == "POST":
        email = request.form["email"]
        password = request.form["password"]
        user = User.query.filter_by(email=email).first()
        if user and check_password_hash(user.password, password):
            return redirect(url_for("dashboard"))
        else:
            return "Invalid email or password"
    return render_template("login.html")

@app.route("/attendance", methods=["GET", "POST"])
def attendance_page():
    if request.method == "POST":
        student_id = request.form["student_id"]
        date = request.form["date"]
        status = request.form["status"]
        attendance = Attendance(student_id=student_id, date=date, status=status)
        db.session.add(attendance)
        db.session.commit()
        return redirect(url_for("attendance"))
    return render_template("attendance.html")

@app.route("/reports", methods=["GET"])
def reports_page():
    attendance_reports = Attendance.query.all()
    return render_template("reports.html", attendance_reports=attendance_reports)

@app.route("/profile", methods=["GET"])
def profile_page():
    user = User.query.filter_by(email="email").first()
    return render_template("profile.html", user=user)

@app.route("/reset_password", methods=["GET", "POST"])
def reset_password_page():
    if request.method == "POST":
        email = request.form["email"]
        user = User.query.filter_by(email=email).first()
        if user:
            new_password = generate_password_hash(request.form["new_password"])
            user.password = new_password
            db.session.commit()
            return redirect(url_for("login"))
        else:
            return "Email not found"
    return render_template("reset_password.html")

@app.route("/dashboard", methods=["GET"])
def dashboard_page():
    attendance_records = Attendance.query.all()
    return render_template("dashboard.html", attendance_records=attendance_records)

@app.route("/logout", methods=["GET"])
def logout_page():
    return redirect(url_for("login"))

if __name__ == "__main__":
    with app.app_context():
        db.create_all()
    app.run(host="0.0.0.0", port=5000, debug=True)


