from flask import Flask, render_template, request, redirect, url_for
from flask_sqlalchemy import SQLAlchemy
import os

app = Flask(__name__)
app.config["DATABASE_URI"] = "sqlite:///attendance.db"
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    email = db.Column(db.String(120), unique=True, nullable=False)
    password = db.Column(db.String(120), nullable=False)

class Attendance(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    attendance_date = db.Column(db.DateTime, nullable=False)
    status = db.Column(db.String(10), nullable=False)

@app.route("/login", methods=["GET", "POST"])
def login():
    if request.method == "POST":
        username = request.form.get("username")
        password = request.form.get("password")
        user = User.query.filter_by(username=username).first()
        if user and user.password == password:
            return redirect(url_for("dashboard"))
    return render_template("login.html")

@app.route("/register", methods=["GET", "POST"])
def register():
    if request.method == "POST":
        username = request.form.get("username")
        email = request.form.get("email")
        password = request.form.get("password")
        user = User(username=username, email=email, password=password)
        db.session.add(user)
        db.session.commit()
        return redirect(url_for("login"))
    return render_template("register.html")

@app.route("/dashboard")
def dashboard():
    return render_template("dashboard.html")

@app.route("/attendance")
def attendance():
    attendances = Attendance.query.all()
    return render_template("attendance.html", attendances=attendances)

@app.route("/mark_attendance", methods=["POST"])
def mark_attendance():
    user_id = request.form.get("user_id")
    attendance_date = request.form.get("attendance_date")
    status = request.form.get("status")
    attendance = Attendance(user_id=user_id, attendance_date=attendance_date, status=status)
    db.session.add(attendance)
    db.session.commit()
    return redirect(url_for("attendance"))

@app.route("/notifications")
def notifications():
    return render_template("notifications.html")

@app.route("/backup")
def backup():
    # backup database data
